{
  "lastUpdated": "2025-05-31",
  "architecture": {
    "ollamaThink": {
      "description": "Parámetro para activar el pensamiento extendido (thinking) en modelos Ollama compatibles como deepseek-r1",
      "implementation": {
        "config": "src/types/config.ts - propiedad ollamaThink?: boolean (default: true)",
        "provider": "src/services/core/ModelProviders.ts - OllamaProvider envía think: true en el body cuando ollamaThink !== false",
        "ui": "src/components/panels/SettingsPanel.tsx - Toggle 'Pensamiento Extendido' en Ollama Advanced"
      },
      "behavior": {
        "default": true (pensamiento activado)",
        "toggle": "Permite desactivar el parámetro think si el usuario lo desea",
        "models": "Modelos compatibles: deepseek-r1 y otros modelos 'thinking' de Ollama"
      }
    }
  }
}
